parameters.jsCode:
const holdings = $input.first().json.body.holdings
const totalValue = holdings.reduce((sum, h) => sum + h.marketValue, 0);

const weightedHoldings = holdings.map(h => ({
  ticker: h.symbol,
  marketValue: h.marketValue,
  weight: h.marketValue / totalValue
}));

return [{
  json: {
    totalPortfolioValue: totalValue,
    holdings: weightedHoldings
  }
}];

const items = $input.all();

const combined = {
  portfolio_exposure: {},
  market_regime: {},
  macro_analysis: {},
  hedge_strategy: {},
  short_squeeze: {},
  ma_radar: {},
  sentiment_arbitrage: {},
  dividend_danger: {},
  institutional_positioning: {}
};

for (const item of items) {
  const data = item.json.output ?? item.json;

  if (data.holdings || data.sector_exposure || data.market_exposure) {
    combined.portfolio_exposure = data;
  } else if (data.market_regime || data.macro_indicators) {
    combined.market_regime = data;
  } else if (data.macro_environment_summary || data.historical_comparisons) {
    combined.macro_analysis = data;
  } else if (data.recommended_hedge) {
    combined.hedge_strategy = data;
  } else if (data.short_squeeze_candidates) {
    combined.short_squeeze = data;
  } else if (data.ma_targets) {
    combined.ma_radar = data;
  } else if (data.sentiment_arbitrage_opportunities) {
    combined.sentiment_arbitrage = data;
  } else if (data.dividend_risk_companies) {
    combined.dividend_danger = data;
  } else if (
    data.new_positions ||
    data.increased_positions ||
    data.reduced_positions ||
    data.exited_positions
  ) {
    combined.institutional_positioning = data;
  }
}

return [{ json: combined }];
